"use client";

// Generated by Copilot
import React, { useEffect, useRef } from 'react';
import { GridStack, type GridStackNode } from 'gridstack';
import 'gridstack/dist/gridstack.min.css';

import { cn } from '@/lib/utils';

export type GridstackPanelPresetId = 'compact' | 'default' | 'wide' | 'xl';

export interface GridstackPanelPreset {
  id: GridstackPanelPresetId;
  label: string;
  cols: number;
  rows: number;
  width: number;
}

export const GRIDSTACK_PANEL_PRESETS: GridstackPanelPreset[] = [
  { id: 'compact', label: 'Compact', cols: 2, rows: 2, width: 280 },
  { id: 'default', label: 'Default', cols: 3, rows: 2, width: 324 },
  { id: 'wide', label: 'Wide', cols: 4, rows: 3, width: 392 },
  { id: 'xl', label: 'XL', cols: 5, rows: 3, width: 456 },
];

function getClosestPreset(cols: number, rows: number) {
  return GRIDSTACK_PANEL_PRESETS.reduce((closest, preset) => {
    const closestScore = Math.abs(closest.cols - cols) + Math.abs(closest.rows - rows);
    const score = Math.abs(preset.cols - cols) + Math.abs(preset.rows - rows);
    return score < closestScore ? preset : closest;
  }, GRIDSTACK_PANEL_PRESETS[1]);
}

interface GridstackPanelSizeSelectorProps {
  value: GridstackPanelPreset;
  onChange: (preset: GridstackPanelPreset) => void;
  className?: string;
}

export function GridstackPanelSizeSelector({ value, onChange, className }: GridstackPanelSizeSelectorProps) {
  const gridRef = useRef<HTMLDivElement | null>(null);
  const apiRef = useRef<GridStack | null>(null);
  const mountedRef = useRef(false);
  const currentPresetRef = useRef<GridstackPanelPreset>(value);

  useEffect(() => {
    currentPresetRef.current = value;
  }, [value]);

  useEffect(() => {
    if (!gridRef.current || mountedRef.current) {
      return;
    }

    const grid = GridStack.init(
      {
        column: 6,
        cellHeight: 18,
        margin: 4,
        float: false,
        acceptWidgets: false,
        resizable: { handles: 'e, se, s' },
      },
      gridRef.current,
    );

    apiRef.current = grid;
    mountedRef.current = true;

    const handleChange = (_event: Event, items: GridStackNode[]) => {
      const item = items[0];
      if (!item?.w || !item?.h) {
        return;
      }
      const nextPreset = getClosestPreset(item.w, item.h);
      if (nextPreset.id !== currentPresetRef.current.id) {
        onChange(nextPreset);
      }
    };

    grid.on('change', handleChange);

    return () => {
      grid.off('change');
      grid.destroy(false);
      apiRef.current = null;
      mountedRef.current = false;
    };
  }, [onChange]);

  useEffect(() => {
    const grid = apiRef.current;
    const widget = gridRef.current?.querySelector('.grid-stack-item');
    if (!grid || !widget) {
      return;
    }

    grid.update(widget as HTMLElement, { w: value.cols, h: value.rows, x: 0, y: 0 });
  }, [value]);

  return (
    <div className={cn('rounded-2xl border border-border bg-card p-3', className)}>
      <div className="mb-3 flex items-center justify-between gap-3">
        <div>
          <p className="text-[11px] uppercase text-text-secondary">GridStack size</p>
          <p className="text-sm font-medium text-text-primary">{value.label}</p>
        </div>
        <p className="text-xs tabular-nums text-text-secondary">{value.width}px</p>
      </div>

      <div ref={gridRef} className="grid-stack h-[7.5rem] rounded-xl border border-border bg-surface-raised/70 p-1">
        <div className="grid-stack-item" gs-x="0" gs-y="0" gs-w={value.cols} gs-h={value.rows}>
          <div className="grid-stack-item-content flex h-full items-center justify-center rounded-xl border border-dashed border-border bg-card px-3 text-center text-[11px] uppercase text-text-secondary">
            Resize this tile to change the panel width
          </div>
        </div>
      </div>

      <div className="mt-3 flex flex-wrap gap-2">
        {GRIDSTACK_PANEL_PRESETS.map((preset) => (
          <button
            key={preset.id}
            type="button"
            onClick={() => onChange(preset)}
            className={cn(
              'rounded-full border px-2.5 py-1 text-[11px] transition-colors',
              preset.id === value.id
                ? 'border-text-display bg-text-display text-black'
                : 'border-border bg-surface text-text-secondary hover:text-text-primary',
            )}
          >
            {preset.label}
          </button>
        ))}
      </div>
    </div>
  );
}

export default GridstackPanelSizeSelector;
